//! JSON-driven AMI pipeline: build, test, and promote in one command.
//!
//! Reads a pipeline configuration from a JSON file (generated by Nix) and
//! orchestrates the entire flow. Eliminates shell script fragility — Nix
//! generates the config, Rust executes it.
//!
//! Config format:
//! ```json
//! {
//!   "template": "/nix/store/.../packer-template.pkr.json",
//!   "ssm_parameter": "/pangea/akeyless-dev/nixos-ami-id",
//!   "region": "us-east-1",
//!   "aws_profile": "akeyless-development",
//!   "packer_vars": { "github_token": "" },
//!   "tests": {
//!     "boot": { "enabled": true, "ssh_user": "root", "instance_type": "t3.medium" },
//!     "vpn":  { "enabled": false, "ssh_user": "root", "instance_type": "t3.medium" }
//!   }
//! }
//! ```

use anyhow::{Context, bail};
use clap::Args;
use serde::Deserialize;
use tracing::info;

use crate::{aws, boot_test, rotate, vpn_test};

const MANIFEST_PATH: &str = "packer-manifest.json";

#[derive(Args)]
pub struct PipelineArgs {
    /// Path to pipeline config JSON (generated by Nix)
    #[arg(long)]
    config: String,

    /// Only run tests (skip packer build, use AMI from SSM)
    #[arg(long)]
    test_only: bool,

    /// Skip all tests (just build + promote)
    #[arg(long)]
    skip_tests: bool,

    /// Show status only
    #[arg(long)]
    status: bool,

    /// Validate config and credentials without building
    #[arg(long)]
    dry_run: bool,
}

/// Pipeline configuration (deserialized from JSON).
#[derive(Debug, Deserialize)]
#[serde(deny_unknown_fields)]
pub struct PipelineConfig {
    /// Path to Packer JSON template
    pub template: String,

    /// SSM parameter for AMI ID storage
    pub ssm_parameter: String,

    /// AWS region
    #[serde(default = "default_region")]
    pub region: String,

    /// AWS profile for credential resolution
    #[serde(default)]
    pub aws_profile: Option<String>,

    /// Packer variable overrides (empty values resolved from env at runtime)
    #[serde(default)]
    pub packer_vars: std::collections::HashMap<String, String>,

    /// Test configuration
    #[serde(default)]
    pub tests: TestConfig,

    /// Optional subnet for test instances
    #[serde(default)]
    pub test_subnet: Option<String>,
}

/// Test gates configuration.
#[derive(Debug, Deserialize, Default)]
#[serde(deny_unknown_fields)]
pub struct TestConfig {
    #[serde(default)]
    pub boot: TestGate,

    #[serde(default)]
    pub vpn: TestGate,
}

/// Individual test gate.
#[derive(Debug, Deserialize)]
#[serde(deny_unknown_fields)]
pub struct TestGate {
    #[serde(default)]
    pub enabled: bool,

    #[serde(default = "default_ssh_user")]
    pub ssh_user: String,

    #[serde(default = "default_instance_type")]
    pub instance_type: String,
}

impl Default for TestGate {
    fn default() -> Self {
        Self {
            enabled: false,
            ssh_user: default_ssh_user(),
            instance_type: default_instance_type(),
        }
    }
}

impl PipelineConfig {
    /// Load AWS config using the profile from pipeline config if specified.
    pub async fn aws_config(&self) -> aws_config::SdkConfig {
        match &self.aws_profile {
            Some(profile) => aws::load_config_with_profile(&self.region, profile).await,
            None => aws::load_config(&self.region).await,
        }
    }
}

fn default_region() -> String { "us-east-1".to_string() }
fn default_ssh_user() -> String { "root".to_string() }
fn default_instance_type() -> String { "t3.medium".to_string() }

/// Run the pipeline.
pub async fn run(args: PipelineArgs) -> anyhow::Result<()> {
    let config_str = std::fs::read_to_string(&args.config)
        .with_context(|| format!("failed to read pipeline config: {}", args.config))?;
    let config: PipelineConfig = serde_json::from_str(&config_str)
        .with_context(|| format!("failed to parse pipeline config: {}", args.config))?;

    info!(
        template = %config.template,
        ssm = %config.ssm_parameter,
        region = %config.region,
        aws_profile = ?config.aws_profile,
        boot_test = config.tests.boot.enabled,
        vpn_test = config.tests.vpn.enabled,
        "Pipeline config loaded"
    );

    // Validate AWS credentials upfront (catches expired SSO before 15-min build)
    let aws_config = config.aws_config().await;
    aws::validate_credentials(&aws_config).await?;

    // Dry-run: validate config + creds, then exit
    if args.dry_run {
        // Verify template exists
        if !std::path::Path::new(&config.template).exists() {
            bail!("Packer template not found: {}", config.template);
        }
        info!("Dry run: config valid, credentials valid, template exists");
        return Ok(());
    }

    // Status-only mode
    if args.status {
        return run_status(&config).await;
    }

    // Test-only mode: test existing AMI from SSM
    if args.test_only {
        let ami_id = get_current_ami(&config).await?;
        info!(ami = %ami_id, "Testing existing AMI from SSM");
        return run_tests(&config, &ami_id).await;
    }

    // Full pipeline: build → test → promote
    let ami_id = run_packer_build(&config).await?;

    if !args.skip_tests {
        if let Err(e) = run_tests(&config, &ami_id).await {
            info!(ami = %ami_id, "Tests FAILED — deregistering AMI");
            let ec2 = aws_sdk_ec2::Client::new(&aws_config);
            rotate::run_rotate(&ec2, &ami_id).await.ok();
            std::fs::remove_file(MANIFEST_PATH).ok();
            bail!("Pipeline failed: {e}");
        }
    }

    // Promote: update SSM
    let ssm = aws_sdk_ssm::Client::new(&aws_config);
    aws::put_ssm_parameter(&ssm, &config.ssm_parameter, &ami_id).await?;
    std::fs::remove_file(MANIFEST_PATH).ok();

    info!(ami = %ami_id, "Pipeline complete — AMI promoted");
    Ok(())
}

/// Run Packer build and return the AMI ID.
async fn run_packer_build(config: &PipelineConfig) -> anyhow::Result<String> {
    info!("Running packer init...");
    let init = std::process::Command::new("packer")
        .args(["init", &config.template])
        .status()
        .context("failed to run packer init")?;
    if !init.success() {
        bail!("packer init failed");
    }

    info!("Running packer build...");
    let mut cmd = std::process::Command::new("packer");
    cmd.args(["build", "-color=false"]);
    for (k, v) in &config.packer_vars {
        // If the value is empty, resolve from environment (e.g. GITHUB_TOKEN)
        let resolved = if v.is_empty() {
            std::env::var(k.to_uppercase()).unwrap_or_default()
        } else {
            v.clone()
        };
        cmd.args(["-var", &format!("{k}={resolved}")]);
    }
    cmd.arg(&config.template);

    let build = cmd.status().context("failed to run packer build")?;
    if !build.success() {
        bail!("packer build failed");
    }

    aws::parse_packer_manifest(MANIFEST_PATH)
}

/// Run enabled test gates against an AMI.
async fn run_tests(config: &PipelineConfig, ami_id: &str) -> anyhow::Result<()> {
    if config.tests.boot.enabled {
        info!("Running boot test...");
        boot_test::run(boot_test::BootTestArgs {
            ami_id: ami_id.to_string(),
            region: config.region.clone(),
            subnet_id: config.test_subnet.clone(),
            instance_type: config.tests.boot.instance_type.clone(),
            timeout: 300,
            ssh_user: config.tests.boot.ssh_user.clone(),
            extra_checks: Vec::new(),
        })
        .await
        .context("boot test failed")?;
        info!("Boot test PASSED");
    }

    if config.tests.vpn.enabled {
        info!("Running VPN test...");
        vpn_test::run(vpn_test::VpnTestArgs {
            ami_id: ami_id.to_string(),
            region: config.region.clone(),
            subnet_id: config.test_subnet.clone(),
            instance_type: config.tests.vpn.instance_type.clone(),
            timeout: 300,
            ssh_user: config.tests.vpn.ssh_user.clone(),
        })
        .await
        .context("VPN test failed")?;
        info!("VPN test PASSED");
    }

    Ok(())
}

/// Get current AMI ID from SSM.
async fn get_current_ami(config: &PipelineConfig) -> anyhow::Result<String> {
    let aws_config = config.aws_config().await;
    let ssm = aws_sdk_ssm::Client::new(&aws_config);
    let resp = ssm
        .get_parameter()
        .name(&config.ssm_parameter)
        .send()
        .await
        .context("SSM GetParameter failed")?;
    resp.parameter()
        .and_then(|p| p.value())
        .map(String::from)
        .context("SSM parameter has no value")
}

/// Show current AMI status.
async fn run_status(config: &PipelineConfig) -> anyhow::Result<()> {
    crate::status::run(crate::status::StatusArgs {
        ssm: Some(config.ssm_parameter.clone()),
        ami_name: None,
        region: config.region.clone(),
    })
    .await
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn parse_valid_config() {
        let json = r#"{
            "template": "/nix/store/abc-template.json",
            "ssm_parameter": "/my/param",
            "region": "us-west-2",
            "aws_profile": "my-profile",
            "packer_vars": {"github_token": ""},
            "tests": {
                "boot": {"enabled": true, "ssh_user": "ec2-user", "instance_type": "t3.small"},
                "vpn": {"enabled": false}
            }
        }"#;
        let config: PipelineConfig = serde_json::from_str(json).unwrap();
        assert_eq!(config.template, "/nix/store/abc-template.json");
        assert_eq!(config.ssm_parameter, "/my/param");
        assert_eq!(config.region, "us-west-2");
        assert_eq!(config.aws_profile.as_deref(), Some("my-profile"));
        assert!(config.tests.boot.enabled);
        assert!(!config.tests.vpn.enabled);
        assert_eq!(config.tests.boot.ssh_user, "ec2-user");
        assert_eq!(config.tests.boot.instance_type, "t3.small");
    }

    #[test]
    fn parse_minimal_config() {
        let json = r#"{"template": "/t.json", "ssm_parameter": "/p"}"#;
        let config: PipelineConfig = serde_json::from_str(json).unwrap();
        assert_eq!(config.region, "us-east-1");
        assert!(config.aws_profile.is_none());
        assert!(!config.tests.boot.enabled);
        assert!(!config.tests.vpn.enabled);
        assert_eq!(config.tests.boot.ssh_user, "root");
        assert_eq!(config.tests.boot.instance_type, "t3.medium");
    }

    #[test]
    fn reject_unknown_fields() {
        let json = r#"{"template": "/t.json", "ssm_parameter": "/p", "typo_field": "oops"}"#;
        let result: Result<PipelineConfig, _> = serde_json::from_str(json);
        assert!(result.is_err(), "should reject unknown fields");
        let err = result.unwrap_err().to_string();
        assert!(err.contains("typo_field"), "error should mention the unknown field");
    }

    #[test]
    fn defaults_applied() {
        let json = r#"{"template": "/t.json", "ssm_parameter": "/p", "tests": {}}"#;
        let config: PipelineConfig = serde_json::from_str(json).unwrap();
        assert_eq!(config.tests.boot.ssh_user, "root");
        assert_eq!(config.tests.vpn.instance_type, "t3.medium");
    }
}
